import { clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs) {
  return twMerge(clsx(inputs));
}

"use client";
import * as CheckboxPrimitive from "@radix-ui/react-checkbox";
import { cn } from "@/lib/utils";
import { cva } from "class-variance-authority";
import { Check } from "lucide-react";

const checkboxVariants = cva(
  "peer shrink-0 flex items-center justify-center rounded-md border shadow-xs transition-all duration-200 focus-visible:outline-none focus-visible:ring-2 disabled:cursor-not-allowed disabled:opacity-50",
  {
    variants: {
      variant: {
        default: "border-primary data-[state=checked]:bg-primary data-[state=checked]:text-primary-foreground",
        secondary: "border-secondary data-[state=checked]:bg-secondary data-[state=checked]:text-secondary-foreground",
        destructive: "border-destructive/60 data-[state=checked]:bg-destructive data-[state=checked]:text-white",
        outline: "border-border bg-transparent data-[state=checked]:bg-transparent data-[state=checked]:text-foreground",
        ghost: "border-transparent bg-muted data-[state=checked]:bg-muted data-[state=checked]:text-foreground",
      },
      size: {
        xs: "size-3",
        sm: "size-3.5",
        default: "size-4",
        lg: "size-5",
      },
    },
    defaultVariants: { variant: "default", size: "default" },
  }
);

function Checkbox({ className, variant = "default", size = "default", ...props }) {
  return (
    <CheckboxPrimitive.Root
      data-slot="checkbox"
      className={cn(checkboxVariants({ variant, size, className }))}
      {...props}
    >
      <CheckboxPrimitive.Indicator className="flex items-center justify-center text-current transition-none">
        <Check className="size-3.5 font-extrabold stroke-3" />
      </CheckboxPrimitive.Indicator>
    </CheckboxPrimitive.Root>
  );
}

export { Checkbox, checkboxVariants };

